import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [isClicked, setIsClicked] = useState(false);

  const handleClick = () => {
    setIsClicked(true);
    setTimeout(() => {
      setIsClicked(false);
    }, 3000); // dura 3 segundos
  };

  return (
    <motion.section
      onClick={handleClick}
      whileHover={{
        backgroundColor: "#154734",
        color: "#ddcba4",
        transition: { duration: 0.3 },
      }}
      animate={{
        scale: isClicked ? 1.07 : 1,
        transition: { duration: 0.3 },
      }}
      style={{
        backgroundColor: "#fff",
        padding: "3rem 2rem",
        marginBottom: "2rem",
        borderRadius: "1rem",
        boxShadow: "0 8px 24px rgba(0, 0, 0, 0.1)",
        color: "#000", // texto normal
        cursor: "pointer",
        ...style,
      }}
    >
      {children}
    </motion.section>
  );
};

export default AnimatedSection;
